import { describe, it } from "node:test";
import assert from "node:assert/strict";
import * as jose from "jose";
import {
  hashRequestContext,
  validateAudience,
  verifyProofOfPossession,
} from "../src/services/credentialVerifier.js";
import {
  validateDelegationLink,
  verifyAttenuation,
} from "../src/services/delegationVerifier.js";
import { buildMappingCacheFromRows } from "../src/services/semanticResolver.js";

describe("Conformance Guards", () => {
  describe("Audience binding", () => {
    it("passes when the credential audience includes the evaluator", () => {
      const result = validateAudience(["svc:claims-api", "svc:audit"], {
        evaluatorId: "svc:claims-api",
      });
      assert.equal(result.pass, true);
      assert.equal(result.check, "pass");
    });

    it("fails closed when the credential audience does not include the evaluator", () => {
      const result = validateAudience("svc:other-api", {
        evaluatorId: "svc:claims-api",
      });
      assert.equal(result.pass, false);
      assert.equal(result.errorCode, "audience_mismatch");
    });
  });

  describe("Proof of possession", () => {
    it("verifies a request-bound proof JWS", async () => {
      const { publicKey, privateKey } = await jose.generateKeyPair("ES256", { extractable: true });
      const publicJwk = await jose.exportJWK(publicKey);
      publicJwk.alg = "ES256";

      const requestContext = {
        action: "claim.settle",
        resource: "claims/auto/CLM-1",
        claimAmount: 3500,
      };
      const credentialId = "urn:uuid:credential-1";
      const presenterId = "agent:claims-negotiator";

      const proof = await new jose.SignJWT({
        credentialId,
        presenterId,
        requestHash: hashRequestContext(requestContext),
      })
        .setProtectedHeader({ alg: "ES256" })
        .setIssuedAt()
        .setExpirationTime("2m")
        .sign(privateKey);

      const result = await verifyProofOfPossession({
        payload: { cnf: { jwk: publicJwk } },
        presenterId,
        credentialId,
        requestContext,
        proofOfPossession: { jws: proof },
      });

      assert.equal(result.pass, true);
      assert.equal(result.check, "pass");
    });

    it("fails closed when the proof is bound to a different request context", async () => {
      const { publicKey, privateKey } = await jose.generateKeyPair("ES256", { extractable: true });
      const publicJwk = await jose.exportJWK(publicKey);
      publicJwk.alg = "ES256";

      const credentialId = "urn:uuid:credential-1";
      const presenterId = "agent:claims-negotiator";
      const proof = await new jose.SignJWT({
        credentialId,
        presenterId,
        requestHash: hashRequestContext({ action: "claim.settle", resource: "claims/auto/CLM-1" }),
      })
        .setProtectedHeader({ alg: "ES256" })
        .setIssuedAt()
        .setExpirationTime("2m")
        .sign(privateKey);

      const result = await verifyProofOfPossession({
        payload: { cnf: { jwk: publicJwk } },
        presenterId,
        credentialId,
        requestContext: { action: "claim.settle", resource: "claims/auto/CLM-2" },
        proofOfPossession: { jws: proof },
      });

      assert.equal(result.pass, false);
      assert.equal(result.errorCode, "proof_of_possession_failed");
    });
  });

  describe("Delegation-chain verification", () => {
    const parent = {
      issuerId: "issuer:claims-authority",
      agentId: "agent:orchestrator",
      credentialId: "credential:parent",
      permissions: ["claim.settle"],
      constraints: [
        { type: "NumericLimitConstraint", field: "core.amount", operator: "lte", value: 5000 },
      ],
    };

    it("requires child issuer-subject continuity and delegatedFrom linkage", () => {
      const child = {
        ...parent,
        issuerId: "agent:orchestrator",
        agentId: "agent:negotiator",
        credentialId: "credential:child",
        delegatedFrom: "credential:parent",
      };

      const result = validateDelegationLink(parent, child);
      assert.equal(result.valid, true);
    });

    it("rejects child credentials issued by a non-parent subject", () => {
      const child = {
        ...parent,
        issuerId: "issuer:claims-authority",
        agentId: "agent:negotiator",
        credentialId: "credential:child",
        delegatedFrom: "credential:parent",
      };

      const result = validateDelegationLink(parent, child);
      assert.equal(result.valid, false);
    });

    it("rejects dropped parent constraints as delegation widening", () => {
      const child = {
        ...parent,
        issuerId: "agent:orchestrator",
        agentId: "agent:negotiator",
        credentialId: "credential:child",
        delegatedFrom: "credential:parent",
        constraints: [],
      };

      const result = verifyAttenuation(parent, child);
      assert.equal(result.valid, false);
      assert.match(result.reason, /dropped constraint/);
    });

    it("allows delegates to lower stateful usage limits", () => {
      const statefulParent = {
        ...parent,
        constraints: [
          { id: "daily-uses", type: "UsageLimitConstraint", maxUses: 5, period: "day", scope: "credential" },
        ],
      };
      const child = {
        ...statefulParent,
        constraints: [
          { id: "daily-uses", type: "UsageLimitConstraint", maxUses: 3, period: "day", scope: "credential" },
        ],
      };

      const result = verifyAttenuation(statefulParent, child);
      assert.equal(result.valid, true);
    });

    it("rejects delegates that raise cumulative stateful limits", () => {
      const statefulParent = {
        ...parent,
        constraints: [
          { id: "daily-total", type: "CumulativeLimitConstraint", field: "core.amount", maxAmount: 5000, period: "day", scope: "credential" },
        ],
      };
      const child = {
        ...statefulParent,
        constraints: [
          { id: "daily-total", type: "CumulativeLimitConstraint", field: "core.amount", maxAmount: 6000, period: "day", scope: "credential" },
        ],
      };

      const result = verifyAttenuation(statefulParent, child);
      assert.equal(result.valid, false);
      assert.match(result.reason, /raised cumulative limit/);
    });
  });

  describe("Governed mapping profiles", () => {
    it("marks conflicting aliases as semantic_alias_conflict", () => {
      const mappings = buildMappingCacheFromRows([
        {
          profile_id: "insurance-claims-v1",
          semantic_field: "insurance.claim_amount",
          local_field: "claimAmount",
          field_type: "number",
          trusted: true,
        },
        {
          profile_id: "insurance-claims-v1",
          semantic_field: "insurance.claim_amount",
          local_field: "amount",
          field_type: "number",
          trusted: true,
        },
      ]);

      assert.equal(mappings.get("insurance.claim_amount").errorCode, "semantic_alias_conflict");
    });

    it("marks expired mappings as mapping_profile_invalid", () => {
      const mappings = buildMappingCacheFromRows([
        {
          profile_id: "insurance-claims-v1",
          semantic_field: "insurance.claim_amount",
          local_field: "claimAmount",
          field_type: "number",
          trusted: true,
          valid_until: "2026-01-01T00:00:00.000Z",
        },
      ], new Date("2026-06-05T00:00:00.000Z"));

      assert.equal(mappings.get("insurance.claim_amount").errorCode, "mapping_profile_invalid");
    });
  });
});
